# ─── Sidebar ─────────────────────────────────────────────────────────────────
with st.sidebar:
    st.markdown("""
    <div style="text-align:center; padding: 1rem 0 0.5rem;">
        <div style="font-size:3rem;">🕉</div>
        <div style="font-family:'Cinzel',serif; color:#ffd700; font-size:1.1rem; margin:0.3rem 0 0.6rem;">Spiritual Coach</div>
        <hr style="border-color:rgba(255,215,0,0.3); margin:0 0 1rem;">
    </div>
    """, unsafe_allow_html=True)

    page = st.radio(
        "Navigate",
        ["🏠 Dashboard", "✨ Affirmations", "📖 Journal", "🌅 Morning Routine", "📿 Sankalp", "🙏 Gratitude"],
        label_visibility="collapsed"
    )
    st.markdown("""
    <div style="text-align:center; margin-top:2rem; font-size:0.75rem; color:rgba(255,215,0,0.45); font-family:'Cinzel',serif;">
        ॐ नमः शिवाय
    </div>
    """, unsafe_allow_html=True)


MOOD_EMOJI = {
    "Peaceful":"☮️","Grateful":"🙏","Happy":"😊","Inspired":"💡",
    "Motivated":"🔥","Anxious":"😰","Sad":"😢","Angry":"😤",
    "Confused":"😕","Hopeful":"🌅"
}
MOODS = list(MOOD_EMOJI.keys())


# ════════════════════════════════════════════════════════
# DASHBOARD
# ════════════════════════════════════════════════════════
if page == "🏠 Dashboard":
    st.markdown('<h1 style="text-align:center;">🕉 Spiritual Coach</h1>', unsafe_allow_html=True)
    st.markdown(f'<p style="text-align:center; color:rgba(255,215,0,0.6); font-size:0.9rem; margin-bottom:1.5rem;">{date.today().strftime("%A, %d %B %Y")}</p>', unsafe_allow_html=True)

    col1, col2, col3 = st.columns(3)
    r1 = requests.get(f"{BASE_URL}/sankalp")
    with col1:
        total_s = len(r1.json()) if r1.status_code == 200 else 0
        st.metric("📿 Total Sankalps", total_s)
    r2 = requests.get(f"{BASE_URL}/gratitude")
    with col2:
        total_g = len(r2.json()) if r2.status_code == 200 else 0
        st.metric("🙏 Gratitude Notes", total_g)
    r3 = requests.get(f"{BASE_URL}/journal/stats/streak")
    with col3:
        streak = r3.json().get("current_streak", 0) if r3.status_code == 200 else 0
        st.metric("🔥 Journal Streak", f"{streak} days")

    st.markdown("<br>", unsafe_allow_html=True)
    col_a, col_b = st.columns(2)

    with col_a:
        st.markdown("### 📿 Today's Sankalp")
        rs = requests.get(f"{BASE_URL}/sankalp/{date.today()}")
        if rs.status_code == 200:
            s = rs.json()
            st.markdown(f'<div class="soul-card"><p style="font-size:1.05rem; color:#fff; font-style:italic;">"{s["sankalp"]}"</p></div>', unsafe_allow_html=True)
        else:
            st.markdown('<div class="soul-card"><p style="color:rgba(255,255,255,0.5);">No Sankalp set today.</p></div>', unsafe_allow_html=True)

    with col_b:
        st.markdown("### 🌅 Morning Routine")
        rm = requests.get(f"{BASE_URL}/morning-routine/{date.today()}")
        if rm.status_code == 200:
            m = rm.json()
            items = {"🚶 Walk": m["walk"], "🧘 Yoga": m["yoga"],
                     "☀️ Surya Arghya": m["surya_arghya"],
                     "💧 Shiva Jal": m["shiva_jal"],
                     "📿 Vishnu Sahasranamam": m["vishnu_sahasranamam"]}
            done = sum(v for v in items.values())
            st.markdown('<div class="soul-card">', unsafe_allow_html=True)
            st.progress(done / 5)
            for k, v in items.items():
                st.markdown(f"{'✅' if v else '⭕'} {k}")
            st.markdown('</div>', unsafe_allow_html=True)
        else:
            st.markdown('<div class="soul-card"><p style="color:rgba(255,255,255,0.5);">No routine logged today.</p></div>', unsafe_allow_html=True)

    st.markdown("### 🙏 Latest Gratitude")
    rg = requests.get(f"{BASE_URL}/gratitude")
    if rg.status_code == 200:
        entries = rg.json()[:3]
        if entries:
            cols = st.columns(len(entries))
            for i, item in enumerate(entries):
                with cols[i]:
                    dt = datetime.fromisoformat(item["created_at"]).strftime("%d %b")
                    st.markdown(f'<div class="soul-card"><p style="font-style:italic; color:#f0e6d3; font-size:0.9rem;">🙏 {item["gratitude"]}</p><p style="font-size:0.7rem; color:rgba(255,215,0,0.5);">{dt}</p></div>', unsafe_allow_html=True)
        else:
            st.info("No gratitude entries yet.")


# ════════════════════════════════════════════════════════
# AFFIRMATIONS
# ════════════════════════════════════════════════════════
elif page == "✨ Affirmations":
    st.markdown("# ✨ Affirmations")
    st.markdown('<p style="color:rgba(255,215,0,0.7);">Plant seeds of positivity in your mind.</p>', unsafe_allow_html=True)

    with st.form("aff_form", clear_on_submit=True):
        aff_text = st.text_input("🌸 New Affirmation", placeholder="I am peaceful, strong, and divine...")
        if st.form_submit_button("💫 Save Affirmation"):
            if not aff_text.strip():
                st.error("Please enter an affirmation.")
            else:
                r = requests.post(f"{BASE_URL}/affirmations", json={"text": aff_text})
                if r.status_code == 200:
                    st.success("Affirmation saved! 🌺")
                else:
                    st.error(r.text)

    st.markdown("### 🌟 Your Affirmations")
    r = requests.get(f"{BASE_URL}/affirmations")
    if r.status_code == 200:
        affs = r.json()
        if affs:
            cols = st.columns(2)
            for i, a in enumerate(reversed(affs)):
                with cols[i % 2]:
                    st.markdown(f'<div class="soul-card"><p style="font-size:1.05rem; color:#f0e6d3; font-style:italic;">✨ {a["text"]}</p><p style="font-size:0.7rem; color:rgba(255,215,0,0.4);">#{a["id"]}</p></div>', unsafe_allow_html=True)
        else:
            st.info("No affirmations yet. Add your first one above!")


# ════════════════════════════════════════════════════════
# JOURNAL
# ════════════════════════════════════════════════════════
elif page == "📖 Journal":
    st.markdown("# 📖 Journal")

    tab1, tab2, tab3 = st.tabs(["✍️ New Entry", "📚 View & Delete", "📊 Stats"])

    with tab1:
        with st.form("journal_form", clear_on_submit=True):
            j_title = st.text_input("📌 Title", placeholder="My reflection for today...")
            j_content = st.text_area("📝 Content", placeholder="Write your thoughts...", height=150)
            j_mood = st.selectbox("💫 Mood", MOODS)
            if st.form_submit_button("💾 Save Journal Entry"):
                if not j_title.strip() or not j_content.strip():
                    st.error("Title and content are required.")
                else:
                    r = requests.post(f"{BASE_URL}/journal", json={"title": j_title, "content": j_content, "mood": j_mood})
                    if r.status_code == 200:
                        st.success("Journal entry saved! 🌺")
                    else:
                        st.error(r.text)

    with tab2:
        col_f1, col_f2 = st.columns(2)
        with col_f1:
            filter_mood = st.selectbox("Filter by Mood", ["All"] + MOODS)
        with col_f2:
            filter_days = st.selectbox("Filter by Period", ["All time", "Last 7 days", "Last 30 days"])
        
        params = {}
        if filter_mood != "All":
            params["mood"] = filter_mood
        if filter_days == "Last 7 days":
            params["days"] = 7
        elif filter_days == "Last 30 days":
            params["days"] = 30

        r = requests.get(f"{BASE_URL}/journal", params=params)
        if r.status_code == 200:
            journals = r.json()
            if not journals:
                st.info("No journal entries found.")
            else:
                for j in journals:
                    me = MOOD_EMOJI.get(j["mood"], "📝")
                    dt = datetime.fromisoformat(j["created_at"]).strftime("%d %b %Y, %I:%M %p")
                    with st.expander(f"{me} {j['title']}  ·  {j['mood']}  ·  {dt}"):
                        st.write(j["content"])
                        if st.button(f"🗑 Delete #{j['id']}", key=f"del_{j['id']}"):
                            rd = requests.delete(f"{BASE_URL}/journal/{j['id']}")
                            if rd.status_code == 200:
                                st.success("Deleted!")
                                st.rerun()
                            else:
                                st.error(rd.text)

    with tab3:
        col_s1, col_s2 = st.columns(2)
        with col_s1:
            r_streak = requests.get(f"{BASE_URL}/journal/stats/streak")
            if r_streak.status_code == 200:
                st.metric("🔥 Current Streak", f"{r_streak.json().get('current_streak', 0)} days")
        with col_s2:
            r_top = requests.get(f"{BASE_URL}/journal/stats/top-moods")
            if r_top.status_code == 200:
                top_data = r_top.json()
                if "top_moods" in top_data and top_data["top_moods"]:
                    top = top_data["top_moods"][0]
                    st.metric("💫 Top Mood", f"{top['mood']}  ({top['count']}×)")

        st.markdown("### 📊 Mood Breakdown")
        r_stats = requests.get(f"{BASE_URL}/journal/stats")
        if r_stats.status_code == 200:
            stats = r_stats.json()
            if stats:
                for s in stats:
                    me = MOOD_EMOJI.get(s["mood"], "📝")
                    bar = "█" * min(s["count"], 20)
                    st.markdown(f'<div style="margin:4px 0; color:#f0e6d3;">{me} <b>{s["mood"]}</b>  <span style="color:rgba(255,215,0,0.7);">{bar}</span> <span style="color:#ffd700;">({s["count"]})</span></div>', unsafe_allow_html=True)
            else:
                st.info("No journal stats yet.")


# ════════════════════════════════════════════════════════
# MORNING ROUTINE
# ════════════════════════════════════════════════════════
elif page == "🌅 Morning Routine":
    st.markdown("# 🌅 Morning Routine")
    st.markdown('<p style="color:rgba(255,215,0,0.7);">Track your sacred morning practices.</p>', unsafe_allow_html=True)

    tab_log, tab_hist = st.tabs(["📋 Log Today", "📅 History"])

    with tab_log:
        r_today = requests.get(f"{BASE_URL}/morning-routine/{date.today()}")
        existing = r_today.json() if r_today.status_code == 200 else None
        dv = lambda k: existing[k] if existing else False

        st.markdown(f"### {date.today().strftime('%A, %d %B %Y')}")
        with st.form("morning_form"):
            col1, col2 = st.columns(2)
            with col1:
                walk  = st.checkbox("🚶 Morning Walk", value=dv("walk"))
                yoga  = st.checkbox("🧘 Yoga", value=dv("yoga"))
                surya = st.checkbox("☀️ Surya Arghya", value=dv("surya_arghya"))
            with col2:
                shiva  = st.checkbox("💧 Shiva Jal", value=dv("shiva_jal"))
                vishnu = st.checkbox("📿 Vishnu Sahasranamam", value=dv("vishnu_sahasranamam"))

            btn = "🔄 Update" if existing else "💾 Save Routine"
            if st.form_submit_button(btn):
                payload = {"walk": walk, "yoga": yoga, "surya_arghya": surya,
                           "shiva_jal": shiva, "vishnu_sahasranamam": vishnu}
                if existing:
                    rr = requests.patch(f"{BASE_URL}/morning-routine/{date.today()}", json=payload)
                else:
                    payload["date"] = str(date.today())
                    rr = requests.post(f"{BASE_URL}/morning-routine", json=payload)
                if rr.status_code == 200:
                    st.success("Routine saved! 🌺")
                    st.rerun()
                else:
                    st.error(rr.text)

        if existing:
            done = sum([existing["walk"], existing["yoga"], existing["surya_arghya"],
                        existing["shiva_jal"], existing["vishnu_sahasranamam"]])
            st.progress(done / 5, text=f"✅ {done}/5 practices completed today")

    with tab_hist:
        r_all = requests.get(f"{BASE_URL}/morning-routine")
        if r_all.status_code == 200:
            routines = r_all.json()
            if not routines:
                st.info("No routines logged yet.")
            else:
                for rt in routines:
                    done = sum([rt["walk"], rt["yoga"], rt["surya_arghya"], rt["shiva_jal"], rt["vishnu_sahasranamam"]])
                    with st.expander(f"📅 {rt['date']}  —  {done}/5 ✅"):
                        for key, label in [("walk","🚶 Walk"),("yoga","🧘 Yoga"),
                                           ("surya_arghya","☀️ Surya Arghya"),
                                           ("shiva_jal","💧 Shiva Jal"),
                                           ("vishnu_sahasranamam","📿 Vishnu Sahasranamam")]:
                            st.markdown(f"{'✅' if rt[key] else '⭕'} {label}")


# ════════════════════════════════════════════════════════
# SANKALP
# ════════════════════════════════════════════════════════
elif page == "📿 Sankalp":
    st.markdown("# 📿 Daily Sankalp")
    st.markdown('<p style="color:rgba(255,215,0,0.7);">One sacred intention — one day at a time.</p>', unsafe_allow_html=True)

    tab_new, tab_all = st.tabs(["🌸 Today", "📜 All Sankalps"])

    with tab_new:
        r_today = requests.get(f"{BASE_URL}/sankalp/{date.today()}")
        if r_today.status_code == 200:
            s = r_today.json()
            st.markdown(f'<div class="soul-card"><h3 style="color:#ffd700; margin-top:0;">Today\'s Sankalp</h3><p style="font-size:1.1rem; font-style:italic; color:#fff;">"{s["sankalp"]}"</p></div>', unsafe_allow_html=True)
            st.info("✅ Today\'s Sankalp is already set.")
        else:
            with st.form("sankalp_form", clear_on_submit=True):
                sankalp_text = st.text_area("🌸 Your Sankalp for Today", placeholder="Today I will be patient and present...", height=100)
                if st.form_submit_button("💫 Set Sankalp"):
                    if not sankalp_text.strip():
                        st.error("Please enter a Sankalp.")
                    else:
                        r = requests.post(f"{BASE_URL}/sankalp", json={"date": str(date.today()), "sankalp": sankalp_text})
                        if r.status_code == 200:
                            st.success("Sankalp saved! 🌺")
                            st.rerun()
                        elif r.status_code == 400:
                            st.warning("Today's Sankalp already exists.")
                        else:
                            st.error(r.text)

    with tab_all:
        r = requests.get(f"{BASE_URL}/sankalp")
        if r.status_code == 200:
            sankalps = r.json()
            if not sankalps:
                st.info("No Sankalps yet.")
            else:
                for s in sankalps:
                    f_icon = "✅" if s.get("fulfilled") else ("❌" if s.get("fulfilled") is False else "🔄")
                    preview = s["sankalp"][:60] + ("..." if len(s["sankalp"]) > 60 else "")
                    with st.expander(f"📅 {s['date']}  {f_icon}  —  {preview}"):
                        st.markdown(f"**Sankalp:** {s['sankalp']}")
                        if s.get("reflection"):
                            st.markdown(f"**Reflection:** {s['reflection']}")
                        if s.get("fulfilled") is not None:
                            st.markdown(f"**Fulfilled:** {'✅ Yes' if s['fulfilled'] else '❌ No'}")


# ════════════════════════════════════════════════════════
# GRATITUDE
# ════════════════════════════════════════════════════════
elif page == "🙏 Gratitude":
    st.markdown("# 🙏 Gratitude Journal")
    st.markdown('<p style="color:rgba(255,215,0,0.7);">A grateful heart is a magnet for miracles.</p>', unsafe_allow_html=True)

    with st.form("gratitude_form", clear_on_submit=True):
        grat_text = st.text_area("🌸 What are you grateful for today?", placeholder="I am grateful for...", height=100)
        if st.form_submit_button("🙏 Save Gratitude"):
            if not grat_text.strip():
                st.error("Please enter your gratitude.")
            else:
                r = requests.post(f"{BASE_URL}/gratitude", json={"gratitude": grat_text})
                if r.status_code == 200:
                    st.success("Gratitude saved! 🌺")
                    st.rerun()
                else:
                    st.error(r.text)

    st.markdown("### 🌸 All Gratitude Entries")
    r = requests.get(f"{BASE_URL}/gratitude")
    if r.status_code == 200:
        entries = r.json()
        if not entries:
            st.info("No gratitude entries yet. Start with one above!")
        else:
            cols = st.columns(2)
            for i, item in enumerate(entries):
                with cols[i % 2]:
                    dt = datetime.fromisoformat(item["created_at"]).strftime("%d %b %Y, %I:%M %p")
                    st.markdown(
                        f'<div class="soul-card"><p style="font-style:italic; color:#f0e6d3; font-size:0.95rem;">🙏 {item["gratitude"]}</p><p style="font-size:0.7rem; color:rgba(255,215,0,0.5);">{dt}</p></div>',
                        unsafe_allow_html=True
                    )